// Генерируем 7 дат, начиная с завтрашнего дня (D+1)
const today = new Date();
const dates = [];
const city = "Samara"; // Город для прогноза

for (let i = 1; i <= 7; i++) {
  const futureDate = new Date(today);
  futureDate.setDate(today.getDate() + i);

  // Форматируем в YYYY-MM-DD
  const year = futureDate.getFullYear();
  const month = String(futureDate.getMonth() + 1).padStart(2, '0');
  const day = String(futureDate.getDate()).padStart(2, '0');

  dates.push(`${year}-${month}-${day}`);
}

// Возвращаем структуру, готовую для отправки в HTTP Request
return [{ json: { city: city, dates: dates } }];

// Получаем ответ от узла HTTP Request
const apiResponse = $input.item.json.json;

// Получаем входные данные (даты) от узла Code (он был на входе перед HTTP-запросом)
const dates = $input.item.json.dates;

const city = apiResponse.city;
const predictions = apiResponse.predictions;
const intervals = apiResponse.confidence_intervals;

let forecastText = "";

// Создаем строки для каждого дня
for (let i = 0; i < dates.length; i++) {
    // Форматируем дату в MM.DD
    const date = dates[i].slice(5).replace('-', '.'); 
    const temp = predictions[i];
    const sign = temp >= 0 ? '+' : ''; 
    const lower = intervals[i].lower;
    const upper = intervals[i].upper;

    forecastText += `*${date}*: ${sign}${temp}°C (Доверие: ${lower}°C - ${upper}°C)\n`;
}

// Собираем финальное сообщение в Markdown для Telegram
const telegramMessage = 
    `☀️ *Еженедельный Прогноз Погоды* ☀️\n\n` +
    `🏙️ *Город:* ${city}\n\n` + // Используем имя города из ответа API
    `📅 *Прогноз на 7 дней:*\n\n` +
    forecastText +
    `\n---\n` +
    `🛠️ *Источник:* Weather Forecast API`; 

// Передаем финальное сообщение
return [{ json: { telegramMessage: telegramMessage } }];
